+// ─── Particle system for environmental effects ──────────────────────
+
+interface Particle {
+  x: number;
+  y: number;
+  vx: number;
+  vy: number;
+  life: number;
+  maxLife: number;
+  color: string;
+  size: number;
+  type: 'dust' | 'spark' | 'drip';
+}
+
+const particles: Particle[] = [];
+
+function spawnParticle(
+  x: number,
+  y: number,
+  color: string,
+  vx: number,
+  vy: number,
+  size: number,
+  life: number,
+  type: 'dust' | 'spark' | 'drip',
+) {
+  if (particles.length > 100) return; // Limit total particles for performance
+  particles.push({ x, y, vx, vy, life, maxLife: life, color, size, type });
+}
+
+export function updateParticles() {
+  for (let i = particles.length - 1; i >= 0; i--) {
+    const p = particles[i];
+    p.x += p.vx;
+    p.y += p.vy;
+    p.life--;
+    // Apply gravity for drips
+    if (p.type === 'drip') {
+      p.vy += 0.05;
+    }
+    // Slow drift for dust
+    if (p.type === 'dust') {
+      p.vx += (Math.random() - 0.5) * 0.02;
+      p.vy += (Math.random() - 0.5) * 0.01;
+    }
+    // Sparks rise and fade with flicker
+    if (p.type === 'spark') {
+      p.vx += (Math.random() - 0.5) * 0.1;
+      p.vy -= 0.02;
+    }
+    if (p.life <= 0) {
+      particles.splice(i, 1);
+    }
+  }
+}
+
+export function drawParticles(ctx: CanvasRenderingContext2D, bounds: { x: number; y: number; w: number; h: number }) {
+  // Spawn dust motes in light beams (top quarter of bounds)
+  if (particles.filter(p => p.type === 'dust').length < 30 && Math.random() < 0.1) {
+    const x = bounds.x + Math.random() * bounds.w;
+    const y = bounds.y + Math.random() * bounds.h * 0.25;
+    spawnParticle(x, y, 'rgba(255,255,255,0.4)', (Math.random() - 0.5) * 0.1, (Math.random() - 0.5) * 0.02, 1, 120, 'dust');
+  }
+
+  // Spawn fireplace sparks near bottom left quarter
+  if (particles.filter(p => p.type === 'spark').length < 20 && Math.random() < 0.05) {
+    const x = bounds.x + bounds.w * 0.1 + Math.random() * bounds.w * 0.3;
+    const y = bounds.y + bounds.h * 0.75 + Math.random() * bounds.h * 0.2;
+    const vx = (Math.random() - 0.5) * 0.3;
+    const vy = -1 - Math.random() * 0.5;
+    const color = `rgba(255,${150 + Math.floor(Math.random() * 100)},0,1)`;
+    const size = 1 + Math.random();
+    const life = 40 + Math.floor(Math.random() * 20);
+    spawnParticle(x, y, color, vx, vy, size, life, 'spark');
+  }
+
+  // Spawn water drips in dungeon (top center)
+  if (particles.filter(p => p.type === 'drip').length < 25 && Math.random() < 0.07) {
+    const x = bounds.x + bounds.w * 0.4 + Math.random() * bounds.w * 0.2;
+    const y = bounds.y + 2;
+    const vx = 0;
+    const vy = 0.5 + Math.random() * 0.3;
+    const color = 'rgba(180,220,255,0.8)';
+    const size = 1 + Math.random();
+    const life = 50 + Math.floor(Math.random() * 20);
+    spawnParticle(x, y, color, vx, vy, size, life, 'drip');
+  }
+
+  // Draw all particles
+  for (const p of particles) {
+    ctx.globalAlpha = p.life / p.maxLife;
+    ctx.fillStyle = p.color;
+    ctx.fillRect(Math.round(p.x), Math.round(p.y), p.size, p.size);
+  }
+  ctx.globalAlpha = 1;
+}
+
+// ─── Ambient particles ─────────────────────────────────────────────
+
+function spawnRoomParticles(type: CharacterType, rid: string, x: number, y: number, w: number, h: number, frame: number) {
+  if (frame % 8 !== 0) return;
+  switch (type) {
+    case 'blacksmith':
+      if (frame % 12 === 0) {
+        spawnParticle(rid, x + w * 0.15, y + h * 0.25, '#f0a030', (Math.random() - 0.5) * 1.5, -1.5, 2, 30);
+        spawnParticle(rid, x + w * 0.18, y + h * 0.28, '#e06020', (Math.random() - 0.5), -1, 1.5, 25);
+      }
+      break;
+    case 'healer':
+      if (frame % 16 === 0) {
+        const a = Math.random() * Math.PI * 2, r = Math.min(w, h) * 0.15;
+        spawnParticle(rid, x + w * 0.55 + Math.cos(a) * r, y + h * 0.68 + Math.sin(a) * r, '#40e080', 0, -0.3, 2, 50);
+      }
+      break;
+    case 'scribe':
+      if (frame % 24 === 0) spawnParticle(rid, x + Math.random() * w, y + h * 0.4, '#8a7a5a', 0.1, -0.1, 1, 80);
+      break;
+    case 'king':
+      if (frame % 32 === 0) spawnParticle(rid, x + w * 0.5 + (Math.random() - 0.5) * 30, y + h * 0.3, P.gold[4], 0, -0.2, 2, 40);
+      break;
+    case 'sentinel':
+      if (frame % 20 === 0) {
+        spawnParticle(rid, x + w * 0.25 + Math.random() * w * 0.5, y + h * 0.04 + Math.random() * h * 0.25, '#ffffff', 0, 0, 1.5, 20);
+      }
+      break;
+  }
+}
